esphome:
  name: openshrooly
  name_add_mac_suffix: true
  friendly_name: OpenShrooly
  project:
    name: grahamsz.openshrooly
    version: ${device_version}
  platformio_options:
    build_flags:
      - -Wno-cpp  # Suppress preprocessor warnings (including deprecation warnings)

  on_boot:
    priority: 600  # Very early boot
    then:
      # Start SWD programming immediately
      - lambda: |-
          ESP_LOGI("boot", "Starting SWD programming early...");
      - swd_programmer.program: swd

      # Wait 3 seconds for SWD to get going, then LVGL will initialize
      - delay: 3s

      - lambda: |-
          ESP_LOGI("boot", "LVGL should initialize now with main page...");

      # Force main page to show after LVGL initializes
      - delay: 200ms
      - lambda: |-
          ESP_LOGI("boot", "Forcing main page display...");
      - lvgl.page.show: aaaa
      - delay: 100ms  # Small delay between page show and update
      - component.update: my_display

      # Wait for SWD programming to complete (typically takes 5-7 seconds total)
      - delay: 5s
      - lambda: |-
          ESP_LOGI("boot", "SWD programming should be complete, starting fan control...");

      # Continue with normal boot sequence
      - script.stop: fan_rpm_check
      - script.stop: fan_stop_check
      - script.execute: air_exchange_manager
      - script.execute: touch_button_monitor

      # Restart WiFi AP after 5 seconds to ensure DHCP server is running
      - delay: 5s
      - script.execute: wifi_ap_bounce
      - script.wait: wifi_ap_bounce
      - delay: 4s
      - script.execute: wifi_ap_boot_verify
      - script.execute: ensure_device_name

      # Wait until humidity is valid
      - wait_until:
          condition:
            lambda: 'return !isnan(id(humidity).state);'
          timeout: 30s

      # Start humidity control
      - lambda: |-
          ESP_LOGI("boot", "🌊 Humidity sensor ready, starting humidity control manager");
      - script.execute: humidity_control_manager

