void WebServer::handleRequest(AsyncWebServerRequest *request) {
  // Store the URL to prevent temporary string destruction
  const auto &url = request->url();

#ifdef USE_ARDUINO
  // Handle events FIRST before /esphome prefix check
  if (url == "/events" || url == "/esphome/events") {
    this->events_.add_new_client(this, request);
    return;
  }
#endif

#ifdef USE_WEBSERVER_APP_HTML_INCLUDE
  // Handle ESPHome index page
  if (url == "/esphome" || url == "/esphome/" || url == "/esphome/index.html") {
    this->handle_index_request(request);
    return;
  }

#endif

  if (url == "/") {
#ifdef USE_WEBSERVER_APP_HTML_INCLUDE
    this->handle_app_request(request);
#else
    this->handle_index_request(request);
#endif
    return;
  }

#ifdef USE_WEBSERVER_CSS_INCLUDE
  if (url == "/0.css") {
    this->handle_css_request(request);
    return;
  }
#endif

#ifdef USE_WEBSERVER_JS_INCLUDE
  if (url == "/0.js") {
    this->handle_js_request(request);
    return;
  }
#endif

#ifdef USE_WEBSERVER_PRIVATE_NETWORK_ACCESS
  if (request->method() == HTTP_OPTIONS && request->hasHeader(HEADER_CORS_REQ_PNA)) {
    this->handle_pna_cors_request(request);
    return;
  }
#endif

  // See comment in canHandle() for why we store the URL reference
  // Check if URL has /esphome/ prefix and strip it for entity handlers
  const char* url_for_matching = url.c_str();
  size_t url_len = url.length();

  if (url.starts_with("/esphome/") && url.length() > 9) {
    // Strip the /esphome prefix, keeping the trailing /
    url_for_matching = url.c_str() + 8;  // Skip "/esphome"
    url_len = url.length() - 8;
  }

  UrlMatch match = match_url(url_for_matching, url_len, false);

#ifdef USE_SENSOR
  if (match.domain_equals("sensor")) {
    this->handle_sensor_request(request, match);
    return;
  }
#endif

#ifdef USE_SWITCH
  if (match.domain_equals("switch")) {
    this->handle_switch_request(request, match);
    return;
  }
#endif

#ifdef USE_BUTTON
  if (match.domain_equals("button")) {
    this->handle_button_request(request, match);
    return;
  }
#endif

#ifdef USE_BINARY_SENSOR
  if (match.domain_equals("binary_sensor")) {
    this->handle_binary_sensor_request(request, match);
    return;
  }
#endif

#ifdef USE_FAN
  if (match.domain_equals("fan")) {
    this->handle_fan_request(request, match);
    return;
  }
#endif

#ifdef USE_LIGHT
  if (match.domain_equals("light")) {
    this->handle_light_request(request, match);
    return;
  }
#endif

#ifdef USE_TEXT_SENSOR
  if (match.domain_equals("text_sensor")) {
    this->handle_text_sensor_request(request, match);
    return;
  }
#endif

#ifdef USE_COVER
  if (match.domain_equals("cover")) {
    this->handle_cover_request(request, match);
    return;
  }
#endif

#ifdef USE_NUMBER
  if (match.domain_equals("number")) {
    this->handle_number_request(request, match);
    return;
  }
#endif

#ifdef USE_DATETIME_DATE
  if (match.domain_equals("date")) {
    this->handle_date_request(request, match);
    return;
  }
#endif

#ifdef USE_DATETIME_TIME
  if (match.domain_equals("time")) {
    this->handle_time_request(request, match);
    return;
  }
#endif

#ifdef USE_DATETIME_DATETIME
  if (match.domain_equals("datetime")) {
    this->handle_datetime_request(request, match);
    return;
  }
#endif

#ifdef USE_TEXT
  if (match.domain_equals("text")) {
    this->handle_text_request(request, match);
    return;
  }
#endif

#ifdef USE_SELECT
  if (match.domain_equals("select")) {
    this->handle_select_request(request, match);
    return;
  }
#endif

#ifdef USE_CLIMATE
  if (match.domain_equals("climate")) {
    this->handle_climate_request(request, match);
    return;
  }
#endif

#ifdef USE_LOCK
  if (match.domain_equals("lock")) {
    this->handle_lock_request(request, match);

    return;
  }
#endif

#ifdef USE_VALVE
  if (match.domain_equals("valve")) {
    this->handle_valve_request(request, match);
    return;
  }
#endif

#ifdef USE_ALARM_CONTROL_PANEL
  if (match.domain_equals("alarm_control_panel")) {
    this->handle_alarm_control_panel_request(request, match);

    return;
  }
#endif

#ifdef USE_UPDATE
  if (match.domain_equals("update")) {
    this->handle_update_request(request, match);
    return;
  }
#endif

  // No matching handler found
#ifdef USE_WEBSERVER_APP_HTML_INCLUDE
  // For the app, handle this as either a static file or an app route (SPA routing)
  ESP_LOGV(TAG, "Request for unknown URL, checking if app resource: %s", request->url().c_str());
  if (url.indexOf('.') > 0) {
    // Has a file extension, treat as static file
    this->handle_static_file_request(request);
  } else {
    // No extension, treat as an app route (SPA routing) - serve the main app HTML
    this->handle_app_request(request);
  }
#else
  // No app configured, send 404
  ESP_LOGV(TAG, "Request for unknown URL: %s", request->url().c_str());
  request->send(404, "text/plain", "Not Found");
#endif
}

bool WebServer::isRequestHandlerTrivial() const { return false; }

void WebServer::add_sorting_info_(JsonObject &root, EntityBase *entity) {
#ifdef USE_WEBSERVER_SORTING
  if (this->sorting_entitys_.find(entity) != this->sorting_entitys_.end()) {
    root["sorting_weight"] = this->sorting_entitys_[entity].weight;
