std::string WebServer::get_content_type_(const std::string &path) {
  if (path.find(".html") != std::string::npos) return "text/html";
  if (path.find(".htm") != std::string::npos) return "text/html";
  if (path.find(".css") != std::string::npos) return "text/css";
  if (path.find(".js") != std::string::npos) return "application/javascript";
  if (path.find(".json") != std::string::npos) return "application/json";
  if (path.find(".png") != std::string::npos) return "image/png";
  if (path.find(".jpg") != std::string::npos) return "image/jpeg";
  if (path.find(".jpeg") != std::string::npos) return "image/jpeg";
  if (path.find(".gif") != std::string::npos) return "image/gif";
  if (path.find(".svg") != std::string::npos) return "image/svg+xml";
  if (path.find(".ico") != std::string::npos) return "image/x-icon";
  if (path.find(".xml") != std::string::npos) return "text/xml";
  if (path.find(".pdf") != std::string::npos) return "application/pdf";
  if (path.find(".zip") != std::string::npos) return "application/zip";
  if (path.find(".woff") != std::string::npos) return "font/woff";
  if (path.find(".woff2") != std::string::npos) return "font/woff2";
  if (path.find(".ttf") != std::string::npos) return "font/ttf";
  if (path.find(".eot") != std::string::npos) return "application/vnd.ms-fontobject";
  return "text/plain";
}

#ifdef USE_WEBSERVER_APP_HTML_INCLUDE
void WebServer::handle_app_request(AsyncWebServerRequest *request) {
#ifndef USE_ESP8266
  AsyncWebServerResponse *response =
      request->beginResponse(200, "text/html", ESPHOME_WEBSERVER_APP_HTML_INCLUDE, ESPHOME_WEBSERVER_APP_HTML_INCLUDE_SIZE);
#else
  AsyncWebServerResponse *response =
      request->beginResponse_P(200, "text/html", ESPHOME_WEBSERVER_APP_HTML_INCLUDE, ESPHOME_WEBSERVER_APP_HTML_INCLUDE_SIZE);
#endif
  response->addHeader("Content-Encoding", "gzip");
  request->send(response);
}
#endif

void WebServer::handle_static_file_request(AsyncWebServerRequest *request) {
#ifdef USE_WEBSERVER_APP_HTML_INCLUDE
  std::string url = request->url().c_str();

  // Search for matching static file
  for (size_t i = 0; i < STATIC_FILES_COUNT; i++) {
    if (url == STATIC_FILES[i].url) {
      ESP_LOGD(TAG, "Serving static file: %s", url.c_str());
#ifndef USE_ESP8266
      AsyncWebServerResponse *response =
          request->beginResponse(200, STATIC_FILES[i].content_type, STATIC_FILES[i].data, STATIC_FILES[i].size);
#else
      AsyncWebServerResponse *response =
          request->beginResponse_P(200, STATIC_FILES[i].content_type, STATIC_FILES[i].data, STATIC_FILES[i].size);
#endif
      response->addHeader("Content-Encoding", "gzip");
      response->addHeader("Cache-Control", "public, max-age=31536000, immutable");
      request->send(response);
      return;
    }
  }
#endif

  ESP_LOGW(TAG, "Static file not found: %s", request->url().c_str());
  request->send(404, "text/plain", "Not Found");

