const express = require('express');
const cors = require('cors');
const pool = require('./db/pool');

const app = express();
const PORT = process.env.PORT || 3030;
const API_KEY = process.env.API_KEY;

app.use(cors());
app.use(express.json());

// API key middleware for write endpoints
function requireApiKey(req, res, next) {
  const key = req.headers['x-api-key'];
  if (!API_KEY || key === API_KEY) return next();
  res.status(401).json({ error: 'Invalid API key' });
}

// Health check
app.get('/api/health', async (req, res) => {
  try {
    await pool.query('SELECT 1');
    res.json({ status: 'ok' });
  } catch {
    res.status(500).json({ status: 'error' });
  }
});

// POST /api/readings - receive data from Shrooly device
app.post('/api/readings', requireApiKey, async (req, res) => {
  const { temperature, humidity, water_level, fan_rpm, device_id } = req.body;

  try {
    const result = await pool.query(
      `INSERT INTO sensor_readings (device_id, temperature, humidity, water_level, fan_rpm)
       VALUES ($1, $2, $3, $4, $5)
       RETURNING id, created_at`,
      [device_id || 'shrooly-1', temperature, humidity, water_level, fan_rpm]
    );
    res.status(201).json(result.rows[0]);
  } catch (err) {
    console.error('Failed to insert reading:', err);
    res.status(500).json({ error: 'Failed to store reading' });
  }
});

// GET /api/readings/latest - most recent reading
app.get('/api/readings/latest', async (req, res) => {
  const deviceId = req.query.device_id || 'shrooly-1';
  try {
    const result = await pool.query(
      `SELECT * FROM sensor_readings WHERE device_id = $1 ORDER BY created_at DESC LIMIT 1`,
      [deviceId]
    );
    res.json(result.rows[0] || null);
  } catch (err) {
    console.error('Failed to fetch latest reading:', err);
    res.status(500).json({ error: 'Failed to fetch reading' });
  }
});

// GET /api/readings - historical readings with optional time range
app.get('/api/readings', async (req, res) => {
  const deviceId = req.query.device_id || 'shrooly-1';
  const hours = parseInt(req.query.hours) || 24;
  const limit = Math.min(parseInt(req.query.limit) || 1000, 10000);

  try {
    const result = await pool.query(
      `SELECT * FROM sensor_readings
       WHERE device_id = $1 AND created_at > NOW() - INTERVAL '1 hour' * $2
       ORDER BY created_at DESC
       LIMIT $3`,
      [deviceId, hours, limit]
    );
    res.json(result.rows);
  } catch (err) {
    console.error('Failed to fetch readings:', err);
    res.status(500).json({ error: 'Failed to fetch readings' });
  }
});

// GET /api/readings/stats - aggregated stats for a time period
app.get('/api/readings/stats', async (req, res) => {
  const deviceId = req.query.device_id || 'shrooly-1';
  const hours = parseInt(req.query.hours) || 24;

  try {
    const result = await pool.query(
      `SELECT
         COUNT(*) as reading_count,
         ROUND(AVG(temperature)::numeric, 1) as avg_temperature,
         ROUND(MIN(temperature)::numeric, 1) as min_temperature,
         ROUND(MAX(temperature)::numeric, 1) as max_temperature,
         ROUND(AVG(humidity)::numeric, 1) as avg_humidity,
         ROUND(MIN(humidity)::numeric, 1) as min_humidity,
         ROUND(MAX(humidity)::numeric, 1) as max_humidity,
         ROUND(AVG(water_level)::numeric, 0) as avg_water_level,
         MIN(created_at) as first_reading,
         MAX(created_at) as last_reading
       FROM sensor_readings
       WHERE device_id = $1 AND created_at > NOW() - INTERVAL '1 hour' * $2`,
      [deviceId, hours]
    );
    res.json(result.rows[0]);
  } catch (err) {
    console.error('Failed to fetch stats:', err);
    res.status(500).json({ error: 'Failed to fetch stats' });
  }
});

// Auto-initialize database on startup
async function initDb() {
  try {
    await pool.query(`
      CREATE TABLE IF NOT EXISTS sensor_readings (
        id BIGSERIAL PRIMARY KEY,
        device_id TEXT NOT NULL DEFAULT 'shrooly-1',
        temperature REAL,
        humidity REAL,
        water_level REAL,
        fan_rpm REAL,
        created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
      );
      CREATE INDEX IF NOT EXISTS idx_readings_device_time
        ON sensor_readings (device_id, created_at DESC);
      CREATE INDEX IF NOT EXISTS idx_readings_created_at
        ON sensor_readings (created_at DESC);
    `);
    console.log('Database ready');
  } catch (err) {
    console.error('Database init failed:', err);
    process.exit(1);
  }
}

initDb().then(() => {
  app.listen(PORT, '0.0.0.0', () => {
    console.log(`Shrooly API listening on port ${PORT}`);
  });
});
